import{c as t,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"The Decoder — 2026-05-21","description":"","frontmatter":{"title":"The Decoder — 2026-05-21","date":"2026-05-21T00:00:00.000Z","source":"The Decoder","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-21-the-decoder.md","filePath":"research/ai-news/2026-05/2026-05-21-the-decoder.md","lastUpdated":1779894392000}'),s={name:"research/ai-news/2026-05/2026-05-21-the-decoder.md"};function i(n,e,l,d,p,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="🔓-the-decoder-—-2026-05-21" tabindex="-1">🔓 The Decoder — 2026-05-21 <a class="header-anchor" href="#🔓-the-decoder-—-2026-05-21" aria-label="Permalink to &quot;🔓 The Decoder — 2026-05-21&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="deepseek-wants-to-take-on-claude-code-and-openai-s-codex-with-deepseek-code" tabindex="-1"><a href="https://the-decoder.com/deepseek-wants-to-take-on-claude-code-and-openais-codex-with-deepseek-code/" target="_blank" rel="noreferrer">Deepseek wants to take on Claude Code and OpenAI&#39;s Codex with &quot;Deepseek Code&quot;</a> <a class="header-anchor" href="#deepseek-wants-to-take-on-claude-code-and-openai-s-codex-with-deepseek-code" aria-label="Permalink to &quot;[Deepseek wants to take on Claude Code and OpenAI&#39;s Codex with &quot;Deepseek Code&quot;](https://the-decoder.com/deepseek-wants-to-take-on-claude-code-and-openais-codex-with-deepseek-code/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-20</em></p><p>Deepseek is building a new team in Beijing to develop its own AI code agent, working title &quot;Deepseek Code,&quot; a direct competitor to Claude Code, Codex, and Cursor. Applicants should know agent loops, MCP, and context engineering and be heavy users of existing coding tools.</p><p>The article <a href="https://the-decoder.com/deepseek-wants-to-take-on-claude-code-and-openais-codex-with-deepseek-code/" target="_blank" rel="noreferrer">Deepseek wants to take on Claude Code and OpenAI&#39;s Codex with &quot;Deepseek Code&quot;</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="linkedin-s-war-on-ai-slop-is-not-just-a-policy-update—it-is-an-admission-that-the-platform-lost-control-of-its-feed" tabindex="-1"><a href="https://the-decoder.com/linkedins-war-on-ai-slop-is-not-just-a-policy-update-it-is-an-admission-that-the-platform-lost-control-of-its-feed/" target="_blank" rel="noreferrer">LinkedIn&#39;s war on AI slop is not just a policy update—it is an admission that the platform lost control of its feed</a> <a class="header-anchor" href="#linkedin-s-war-on-ai-slop-is-not-just-a-policy-update—it-is-an-admission-that-the-platform-lost-control-of-its-feed" aria-label="Permalink to &quot;[LinkedIn&#39;s war on AI slop is not just a policy update—it is an admission that the platform lost control of its feed](https://the-decoder.com/linkedins-war-on-ai-slop-is-not-just-a-policy-update-it-is-an-admission-that-the-platform-lost-control-of-its-feed/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-20</em></p><p>Linkedin is cracking down on AI-generated junk content it calls &quot;AI slop.&quot; In early tests, the platform says it correctly flagged generic posts 94 percent of the time. The irony: parent company Microsoft has been actively pushing AI use on LinkedIn itself.</p><p>The article <a href="https://the-decoder.com/linkedins-war-on-ai-slop-is-not-just-a-policy-update-it-is-an-admission-that-the-platform-lost-control-of-its-feed/" target="_blank" rel="noreferrer">LinkedIn&#39;s war on AI slop is not just a policy update—it is an admission that the platform lost control of its feed</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="google-tests-the-app-market-version-of-the-saaspocalypse" tabindex="-1"><a href="https://the-decoder.com/google-tests-the-app-version-of-the-saaspocalypse/" target="_blank" rel="noreferrer">Google tests the app market version of the SaaSpocalypse</a> <a class="header-anchor" href="#google-tests-the-app-market-version-of-the-saaspocalypse" aria-label="Permalink to &quot;[Google tests the app market version of the SaaSpocalypse](https://the-decoder.com/google-tests-the-app-version-of-the-saaspocalypse/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-20</em></p><p>Google AI Studio can now generate native Android apps from a prompt - built in Kotlin with Jetpack Compose and testable in a browser emulator. For simple utility apps like trackers or checklists, the Play Store could become less and less relevant. Apple is taking the opposite approach, consistently blocking vibe-coding apps.</p><p>The article <a href="https://the-decoder.com/google-tests-the-app-version-of-the-saaspocalypse/" target="_blank" rel="noreferrer">Google tests the app market version of the SaaSpocalypse</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="stability-ai-launches-stable-audio-3-0-with-up-to-six-minute-tracks-and-open-weights" tabindex="-1"><a href="https://the-decoder.com/stability-ai-launches-stable-audio-3-0-with-up-to-six-minute-tracks-and-open-weights/" target="_blank" rel="noreferrer">Stability AI launches Stable Audio 3.0 with up to six-minute tracks and open weights</a> <a class="header-anchor" href="#stability-ai-launches-stable-audio-3-0-with-up-to-six-minute-tracks-and-open-weights" aria-label="Permalink to &quot;[Stability AI launches Stable Audio 3.0 with up to six-minute tracks and open weights](https://the-decoder.com/stability-ai-launches-stable-audio-3-0-with-up-to-six-minute-tracks-and-open-weights/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-20</em></p><p>Stability AI has unveiled Stable Audio 3.0, a new generation of audio models - three of which ship with open weights. The models generate music tracks up to six minutes long and were trained entirely on licensed data, according to the company.</p><p>The article <a href="https://the-decoder.com/stability-ai-launches-stable-audio-3-0-with-up-to-six-minute-tracks-and-open-weights/" target="_blank" rel="noreferrer">Stability AI launches Stable Audio 3.0 with up to six-minute tracks and open weights</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="google-pairs-its-genie-world-model-with-street-view-to-create-explorable-ai-worlds-based-on-real-places" tabindex="-1"><a href="https://the-decoder.com/google-pairs-its-genie-world-model-with-street-view-to-create-explorable-ai-worlds-based-on-real-places/" target="_blank" rel="noreferrer">Google pairs its Genie world model with Street View to create explorable AI worlds based on real places</a> <a class="header-anchor" href="#google-pairs-its-genie-world-model-with-street-view-to-create-explorable-ai-worlds-based-on-real-places" aria-label="Permalink to &quot;[Google pairs its Genie world model with Street View to create explorable AI worlds based on real places](https://the-decoder.com/google-pairs-its-genie-world-model-with-street-view-to-create-explorable-ai-worlds-based-on-real-places/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-20</em></p><p>Google Deepmind connects its Genie 3 world model to Street View imagery: users drop a pin on a map and get a walkable, AI-generated world based on a real place. Google&#39;s Street View data, collected over many years, becomes a strategic training resource for creative demos, but above all for AI agents and robots.</p><p>The article <a href="https://the-decoder.com/google-pairs-its-genie-world-model-with-street-view-to-create-explorable-ai-worlds-based-on-real-places/" target="_blank" rel="noreferrer">Google pairs its Genie world model with Street View to create explorable AI worlds based on real places</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const m=t(s,[["render",i]]);export{u as __pageData,m as default};
